mapper.select:
SELECT r.*, te.teacher_name AS teacherName, stu.stu_name AS stuName FROM review r LEFT JOIN teacher te ON r.teacher_id = te.teacher_id LEFT JOIN submission sub ON r.submission_id = sub.submission_id LEFT JOIN selection sel ON sub.selection_id = sel.selection_id LEFT JOIN student stu ON sel.stu_id = stu.stu_id WHERE r.submission_id IN
#{id}
ORDER BY r.review_time DESC
